import SwiftUI\n\n/// Main chat interface: message list + input bar\nstruct ChatView: View {\n    @ObservedObject var viewModel: ChatViewModel\n    let toolExecutor: ToolExecutor\n    \n    var body: some View {\n        NavigationView {\n            VStack(spacing: 0) {\n                // Message list\n                ScrollViewReader { proxy in\n                    ScrollView {\n                        LazyVStack(alignment: .leading, spacing: 8) {\n                            if viewModel.messages.isEmpty {\n                                EmptyChatView()\n                            }\n                            \n                            ForEach(viewModel.messages) { msg in\n                                MessageBubbleView(message: msg)\n                                    .id(msg.id)\n                            }\n                            \n                            if let error = viewModel.errorMessage {\n                                Text(error)\n                                    .font(.caption)\n                                    .foregroundColor(.red)\n                                    .padding(.horizontal)\n                            }\n                        }\n                        .padding(.horizontal)\n                        .padding(.vertical, 8)\n                    }\n                    .onChange(of: viewModel.messages.count) { _ in\n                        if let last = viewModel.messages.last {\n                            withAnimation { proxy.scrollTo(last.id, anchor: .bottom) }\n                        }\n                    }\n                    .onChange(of: viewModel.messages.last?.content ?? \\\"\\\") { _ in\n                        if let last = viewModel.messages.last {\n                            proxy.scrollTo(last.id, anchor: .bottom)\n                        }\n                    }\n                }\n                \n                Divider()\n                \n                // Input bar\n                MessageInputBar(\n                    text: $viewModel.inputText,\n                    isStreaming: viewModel.isStreaming,\n                    hasConfig: viewModel.hasConfig,\n                    onSend: { viewModel.sendMessage() },\n                    onStop: { viewModel.stopStreaming() }\n                )\n            }\n            .navigationTitle(\\\"Angles\\\")\n            .navigationBarTitleDisplayMode(.inline)\n            .toolbar {\n                ToolbarItem(placement: .navigationBarTrailing) {\n                    Button(action: viewModel.clearChat) {\n                        Image(systemName: \\\"trash\\\")\n                    }\n                    .disabled(viewModel.messages.isEmpty)\n                }\n                ToolbarItem(placement: .navigationBarLeading) {\n                    if !viewModel.hasConfig {\n                        Label(\\\"No API\\\", systemImage: \\\"exclamationmark.triangle.fill\\\")\n                            .font(.caption)\n                            .foregroundColor(.orange)\n                    }\n                }\n            }\n        }\n        .navigationViewStyle(.stack)\n    }\n}\n\n// MARK: - Empty State\n\nstruct EmptyChatView: View {\n    var body: some View {\n        VStack(spacing: 16) {\n            Spacer().frame(height: 60)\n            Image(systemName: \\\"angle\\\")\n                .font(.system(size: 60))\n                .foregroundColor(.cyan.opacity(0.5))\n            Text(\\\"Angles is ready\\\")\n                .font(Font.title2.weight(.bold))\n            Text(\\\"Ask me to code, browse the web, or manage files.\\\\nI can create, read, write, and delete files.\\\")\n                .font(.subheadline)\n                .foregroundColor(.secondary)\n                .multilineTextAlignment(.center)\n            Spacer()\n        }\n        .frame(maxWidth: .infinity)\n        .padding(.vertical, 100)\n    }\n}